        for (int i = 0; i < totalEntries; i++) {
            Position p = ledger1.addEntry("entry".getBytes());
            entries.add(p);
        }
        // Make ack holes and trigger a mark deletion.
        for (int i = totalEntries - 1; i >= 0; i--) {
            if (i % 2 == 0) {
                cursor1.delete(entries.get(i));
