     * @throws InterruptedException
     * @throws IOException
     */
    public CountDownLatch sleepBookie(BookieId addr, final int seconds)
            throws Exception {
        Optional<ServerTester> tester = byAddress(addr);
        if (tester.isPresent()) {
            CountDownLatch latch = new CountDownLatch(1);
            Thread sleeper = new Thread() {
                @Override
                public void run() {
                    try {
                        tester.get().getServer().suspendProcessing();
                        log.info().attr("bookieAddr", tester.get().getAddress()).log("Bookie is asleep");
                        latch.countDown();
                        Thread.sleep(seconds * 1000);
                        tester.get().getServer().resumeProcessing();
                        log.info().attr("bookieAddr", tester.get().getAddress()).log("Bookie is awake");
                    } catch (Exception e) {
                        log.error().exception(e).log("Error suspending bookie");
                    }
                }
            };
            sleeper.start();
            return latch;
        } else {
            throw new IOException("Bookie not found");
        }
    }

